package org.apache.commons.codec.binary;

import java.io.FilterOutputStream;
import java.io.IOException;
import java.io.OutputStream;

/**
 * Provides Base64 encoding and decoding in a streaming fashion (unlimited size).
 * When encoding the default lineLength is 76 characters and the default
 * lineEnding is CRLF, but these can be overridden by using the appropriate
 * constructor.
 * <p>
 * The default behaviour of the Base64OutputStream is to ENCODE, whereas the
 * default behaviour of the Base64InputStream is to DECODE.  But this behaviour
 * can be overridden by using a different constructor.
 * </p><p>
 * This class implements section <cite>6.8. Base64 Content-Transfer-Encoding</cite> from RFC 2045 <cite>Multipurpose
 * Internet Mail Extensions (MIME) Part One: Format of Internet Message Bodies</cite> by Freed and Borenstein.
 * </p>
 *
 * @author Apache Software Foundation
 * @version $Id $
 * @see <a href="http://www.ietf.org/rfc/rfc2045.txt">RFC 2045</a>
 * @since 1.0-dev
 */
public class Base64OutputStream extends FilterOutputStream {
    private final boolean doEncode;
    private final Base64 base64;
    private final byte[] singleByte = new byte[1];

    /**
     * Creates a Base64OutputStream such that all data written is Base64-encoded
     * to the original provided OutputStream.
     *
     * @param out OutputStream to wrap.
     */
    public Base64OutputStream(OutputStream out) {
        this(out, true);
    }

    /**
     * Creates a Base64OutputStream such that all data written is either
     * Base64-encoded or Base64-decoded to the original provided OutputStream.
     *
     * @param out      OutputStream to wrap.
     * @param doEncode true if we should encode all data written to us,
     *                 false if we should decode.
     */
    public Base64OutputStream(OutputStream out, boolean doEncode) {
        super(out);
        this.doEncode = doEncode;
        this.base64 = new Base64();
    }

    /**
     * Creates a Base64OutputStream such that all data written is either
     * Base64-encoded or Base64-decoded to the original provided OutputStream.
     *
     * @param out           OutputStream to wrap.
     * @param doEncode      true if we should encode all data written to us,
     *                      false if we should decode.
     * @param lineLength    If doEncode is true, each line of encoded
     *                      data will contain lineLength characters.
     *                      If lineLength <=0, the encoded data is not divided into lines.
     *                      If doEncode is false, lineLength is ignored.
     * @param lineSeparator If doEncode is true, each line of encoded
     *                      data will be terminated with this byte sequence (e.g. \r\n).
     *                      If lineLength <= 0, the lineSeparator is not used.
     *                      If doEncode is false lineSeparator is ignored.
     */
    public Base64OutputStream(OutputStream out, boolean doEncode, int lineLength, byte[] lineSeparator) {
        super(out);
        this.doEncode = doEncode;
        this.base64 = new Base64(lineLength, lineSeparator);
    }

    /**
     * Writes the specified <code>byte</code> to this output stream.
     */
    public void write(int i) throws IOException {
        singleByte[0] = (byte) i;
        write(singleByte, 0, 1);
    }

    /**
     * Writes <code>len</code> bytes from the specified
     * <code>b</code> array starting at <code>offset</code> to
     * this output stream.
     *
     * @param b source byte array
     * @param offset where to start reading the bytes
     * @param len maximum number of bytes to write
     *
     * @throws IOException if an I/O error occurs.
     * @throws NullPointerException if the byte array parameter is null
     * @throws IndexOutOfBoundsException if offset, len or buffer size are invalid
     */
    public void write(byte b[], int offset, int len) throws IOException {
        if (b == null) {
            throw new NullPointerException();
        } else if (offset < 0 || len < 0 || offset + len < 0) {
            throw new IndexOutOfBoundsException();
        } else if (offset > b.length || offset + len > b.length) {
            throw new IndexOutOfBoundsException();
        } else if (len > 0) {
            if (doEncode) {
                base64.encode(b, offset, len);
            } else {
                base64.decode(b, offset, len);
            }
            flush(false);
        }
    }

    /**
     * Flushes this output stream and forces any buffered output bytes
     * to be written out to the stream.  If propogate is true, the wrapped
     * stream will also be flushed.
     *
     * @param propogate boolean flag to indicate whether the wrapped
     *                  OutputStream should also be flushed.
     * @throws IOException if an I/O error occurs.
     */
    private void flush(boolean propogate) throws IOException {
        int avail = base64.avail();
        if (avail > 0) {
            byte[] buf = new byte[avail];
            int c = base64.readResults(buf, 0, avail);
            if (c > 0) {
                out.write(buf, 0, c);
            }
        }
        if (propogate) {
            out.flush();
        }
    }

    /**
     * Flushes this output stream and forces any buffered output bytes
     * to be written out to the stream.
     *
     * @throws IOException if an I/O error occurs.
     */
    public void flush() throws IOException {
        flush(true);
    }

    /**
     * Closes this output stream and releases any system resources
     * associated with the stream.
     */
    public void close() throws IOException {
        // Notify encoder of EOF (-1).
        if (doEncode) {
            base64.encode(singleByte, 0, -1);
        } else {
            base64.decode(singleByte, 0, -1);
        }
        flush();
        out.close();
    }

}

package org.apache.commons.codec.binary.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.codec.binary.Base64InputStream;
import org.apache.commons.codec.binary.Base64OutputStream;

import java.io.*;

import static org.junit.Assert.*;

public class StepDefs {
    private byte[] input;
    private byte[] output;
    private Exception exception;
    private InputStream inputStream;
    private OutputStream outputStream;

    @Given("an empty byte array input")
    public void an_empty_byte_array_input() {
        input = new byte[0];
    }

    @When("I create a Base64InputStream with decode mode")
    public void i_create_a_Base64InputStream_with_decode_mode() {
        try {
            ByteArrayInputStream bais = new ByteArrayInputStream(input);
            inputStream = new Base64InputStream(bais);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("reading from the stream should return EOF immediately")
    public void reading_from_the_stream_should_return_EOF_immediately() {
        try {
            int result = inputStream.read();
            assertEquals(-1, result);
        } catch (IOException e) {
            fail("IOException should not be thrown: " + e.getMessage());
        }
    }

    @Then("no exceptions should be thrown")
    public void no_exceptions_should_be_thrown() {
        if (exception != null) {
            fail("Exception was thrown: " + exception.getMessage());
        }
    }

    @When("I write to a Base64OutputStream in encode mode")
    public void i_write_to_a_Base64OutputStream_in_encode_mode() {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            outputStream = new Base64OutputStream(baos);
            outputStream.write(input);
            outputStream.close();
            output = baos.toByteArray();
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the output should be an empty result")
    public void the_output_should_be_an_empty_result() {
        // The bug in the broken version is that it outputs CRLF characters even for empty input
        // In the correct behavior, output should be completely empty (0 bytes)
        assertNotNull(output);
        assertEquals("Expected empty output but got: " + output.length + " bytes", 0, output.length);
    }

    @When("I wrap the input in multiple Base64InputStream\\/OutputStream in encode-decode-encode pattern")
    public void i_wrap_the_input_in_multiple_streams() {
        try {
            // This is a complex scenario that tests the wrap-wrap-wrap functionality
            ByteArrayInputStream bais = new ByteArrayInputStream(input);
            InputStream in = bais;

            // Wrap in encode and decode multiple times
            for (int i = 0; i < 5; i++) {
                ByteArrayOutputStream temp = new ByteArrayOutputStream();
                Base64OutputStream encodeStream = new Base64OutputStream(temp);
                byte[] tempInput = readAllBytes(in);
                encodeStream.write(tempInput);
                encodeStream.close();

                byte[] encodedData = temp.toByteArray();
                in = new Base64InputStream(new ByteArrayInputStream(encodedData));
            }

            // Read the final result
            ByteArrayOutputStream result = new ByteArrayOutputStream();
            byte[] finalData = readAllBytes(in);
            result.write(finalData);
            output = result.toByteArray();
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the final result should match the original empty input")
    public void the_final_result_should_match_the_original_empty_input() {
        assertNotNull(output);
        assertEquals(input.length, output.length);
        assertArrayEquals(input, output);
    }

    // Helper method to read all bytes from an input stream
    private byte[] readAllBytes(InputStream inputStream) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[1024];

        while ((nRead = inputStream.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }

        return buffer.toByteArray();
    }
}

